  { regex: /edg/i, name: "Edge", icon: Icons.BrandEdgeIcon },
  { regex: /opr\\/|opera/i, name: "Opera", icon: Icons.BrandOperaIcon },
  { regex: /chrome|chromium|crios/i, name: "Chrome", icon: Icons.BrandChromeIcon },
